import{_ as e,o as a,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Manage Billing","description":"","frontmatter":{"title":"Manage Billing","slug":"manage-billing"},"headers":[],"relativePath":"account-hub/manage-billing.md","filePath":"account-hub/manage-billing.md"}'),r={name:"account-hub/manage-billing.md"};function o(s,t,l,c,d,u){return a(),n("div",null,[...t[0]||(t[0]=[i('<div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for managing billing, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, attribution windows are configured under <strong>Account</strong> → <a href="./billing-manage-new.html"><strong>Billing</strong></a>.</p></div><h2 id="required-permissions" tabindex="-1">Required permissions <a class="header-anchor" href="#required-permissions" aria-label="Permalink to &quot;Required permissions&quot;">​</a></h2><p>In order to view/edit specific billing details, you need to have the correct access and permission level:</p><table tabindex="0"><thead><tr><th>Billing feature</th><th>Permission requirement</th></tr></thead><tbody><tr><td>- Your Plan - Usage Statistics - Subscribed Products</td><td><strong>View</strong> access to <strong>App-level Settings</strong></td></tr><tr><td>- Payment Info (credit cards) - View/download invoices - Billing contact info</td><td><strong>View</strong> access to <strong>App-level Settings</strong> and <strong>Sensitive Data</strong></td></tr><tr><td>- Change plans - View/download invoices - Cancel subscriptions</td><td><strong>Edit</strong> access to <strong>App-level Settings</strong></td></tr><tr><td>- Add/edit/delete credit card information</td><td><strong>Edit</strong> access to <strong>App-level Settings</strong> and <strong>Sensitive Data</strong></td></tr></tbody></table><p>For additional details on permissions, view our guide <a href="./add-manage-users-roles-permissions-access.html">here</a>.</p><h2 id="access-billing-features" tabindex="-1">Access billing features <a class="header-anchor" href="#access-billing-features" aria-label="Permalink to &quot;Access billing features&quot;">​</a></h2><p>Navigate to the <strong>Billing</strong> tab in the Branch Dashboard to start using billing features.</p><h3 id="your-plan" tabindex="-1">Your plan <a class="header-anchor" href="#your-plan" aria-label="Permalink to &quot;Your plan&quot;">​</a></h3><p>In the <strong>Your Plan</strong> section, you can view your current plan, MAU limit, and monthly cost. Here you will also be able to update your plan by clicking the <strong>Change Plan</strong> button.</p><h3 id="account-summary" tabindex="-1">Account summary <a class="header-anchor" href="#account-summary" aria-label="Permalink to &quot;Account summary&quot;">​</a></h3><p>In the <strong>Account Summary</strong> section, you get quick information on your current plan:</p><ul><li>Last Month&#39;s MAUs</li><li>Account Balance</li><li>Payment Term</li><li>Billing Cycle Day</li><li>Billing Contact Name</li><li>Billing Contact Email</li></ul><h3 id="subscribed-products" tabindex="-1">Subscribed products <a class="header-anchor" href="#subscribed-products" aria-label="Permalink to &quot;Subscribed products&quot;">​</a></h3><p>In the <strong>Subscribed Products</strong> section, you can view which Branch products are/aren&#39;t activated in your Branch account. Here you will be able to navigate to that product to activate it or start a trial.</p><h3 id="invoice-details" tabindex="-1">Invoice details <a class="header-anchor" href="#invoice-details" aria-label="Permalink to &quot;Invoice details&quot;">​</a></h3><p>In the <strong>Invoice Details</strong> section, you can view and download your recent invoices.</p><p>For more details on invoices, view our dedicated guide <a href="./manage-invoices.html">here</a>.</p><h3 id="payment-information" tabindex="-1">Payment information <a class="header-anchor" href="#payment-information" aria-label="Permalink to &quot;Payment information&quot;">​</a></h3><p>In the <strong>Payment Information</strong> section, you can get a quick view of the current payment methods for your Branch account.</p>',19)])])}const m=e(r,[["render",o]]);export{h as __pageData,m as default};
